const cityGroups = [
  { city: "上海", districts: ["浦东新区", "徐汇区", "静安区"] },
  { city: "北京", districts: ["海淀区", "朝阳区", "丰台区"] },
  { city: "深圳", districts: ["南山区", "福田区", "宝安区"] },
  { city: "杭州", districts: ["西湖区", "余杭区", "滨江区"] },
  { city: "广州", districts: ["天河区", "海珠区", "黄埔区"] },
  { city: "成都", districts: ["高新区", "武侯区", "锦江区"] }
];

const companyNames = [
  "星河科技",
  "云图互动",
  "海纳数据",
  "北辰智能",
  "青木未来",
  "光年网络",
  "星火教育",
  "至简医疗",
  "飞羽出行",
  "智谷供应链",
  "晨曦电商",
  "未来智造"
];

const industries = [
  "互联网",
  "智能制造",
  "医疗健康",
  "教育培训",
  "电商零售",
  "物流供应链"
];

const jobFamilies = [
  {
    title: "前端开发工程师",
    tags: ["Vue2", "H5", "TypeScript"],
    category: "技术",
    keywords: ["负责招聘系统前端开发", "优化多端体验", "推动组件化建设"]
  },
  {
    title: "后端开发工程师",
    tags: ["Java", "Spring Boot", "MySQL"],
    category: "技术",
    keywords: ["设计招聘业务接口", "优化数据性能", "保障服务稳定性"]
  },
  {
    title: "产品经理",
    tags: ["需求分析", "B端产品", "增长"],
    category: "产品",
    keywords: ["规划招聘平台路线图", "协同交付项目", "完善数据指标体系"]
  },
  {
    title: "测试工程师",
    tags: ["自动化", "接口测试", "质量保障"],
    category: "技术",
    keywords: ["建立测试策略", "保障招聘流程质量", "推进持续集成"]
  },
  {
    title: "UI设计师",
    tags: ["交互设计", "设计系统", "Figma"],
    category: "设计",
    keywords: ["输出视觉规范", "设计招聘活动页面", "提升转化体验"]
  },
  {
    title: "招商主管",
    tags: ["客户拓展", "渠道合作", "商务谈判"],
    category: "运营",
    keywords: ["拓展企业客户", "制定招商方案", "维护合作关系"]
  },
  {
    title: "校园招聘专员",
    tags: ["雇主品牌", "校招运营", "活动执行"],
    category: "HR",
    keywords: ["统筹校招项目", "维护院校资源", "组织宣讲活动"]
  }
];

const benefitsPool = [
  "六险一金",
  "弹性上班",
  "年度体检",
  "带薪年假",
  "双休",
  "绩效奖金",
  "餐补",
  "租房补贴",
  "节日礼金",
  "年度旅游"
];

const employmentTypes = ["全职", "实习", "校招", "社招"];
const educationLevels = ["大专", "本科", "硕士"];
const experiences = ["1-3年", "3-5年", "5-10年", "经验不限"];

const companies = companyNames.map((name, index) => {
  const cityInfo = cityGroups[index % cityGroups.length];
  return {
    id: `company-${index + 1}`,
    name,
    industry: industries[index % industries.length],
    city: cityInfo.city,
    district: cityInfo.districts[index % cityInfo.districts.length],
    scale: `${200 + index * 60}-${400 + index * 120}人`,
    financing: ["A轮", "B轮", "C轮", "已上市"][index % 4],
    rating: Number((4.5 + (index % 5) * 0.08).toFixed(1)),
    openJobs: 28 + index * 5,
    summary: `${name}专注${industries[index % industries.length]}赛道，为企业与人才提供高效协同的数字化方案。`
  };
});

const jobs = Array.from({ length: 420 }, (_, index) => {
  const family = jobFamilies[index % jobFamilies.length];
  const company = companies[index % companies.length];
  const cityInfo = cityGroups[index % cityGroups.length];
  const district = cityInfo.districts[(index + 1) % cityInfo.districts.length];
  const salaryMin = 8 + (index % 10) * 2;
  const salaryMax = salaryMin + 6 + (index % 5) * 2;
  const publishedDays = (index % 14) + 1;
  const benefitOffset = index % benefitsPool.length;

  return {
    id: `job-${index + 1}`,
    title: family.title,
    companyId: company.id,
    company: company.name,
    industry: company.industry,
    category: family.category,
    city: cityInfo.city,
    district,
    location: `${cityInfo.city} · ${district}`,
    salary: `${salaryMin}k-${salaryMax}k`,
    salaryMin,
    salaryMax,
    experience: experiences[index % experiences.length],
    education: educationLevels[index % educationLevels.length],
    employmentType: employmentTypes[index % employmentTypes.length],
    tags: family.tags.concat([company.financing]),
    benefits: [
      benefitsPool[benefitOffset],
      benefitsPool[(benefitOffset + 2) % benefitsPool.length],
      benefitsPool[(benefitOffset + 4) % benefitsPool.length]
    ],
    publishedAt: `${publishedDays}天前`,
    applicants: 35 + (index % 60) * 3,
    urgent: index % 9 === 0,
    remote: index % 7 === 0,
    description: [
      `${family.keywords[0]}，与产品、设计、运营团队共同推进关键项目。`,
      `${family.keywords[1]}，持续提升招聘转化效率与平台稳定性。`,
      `${family.keywords[2]}，沉淀标准化方法与可复用的业务能力。`
    ],
    requirements: [
      `具备${family.tags[0]}相关实践经验，理解业务需求并能独立交付。`,
      `熟悉${family.tags[1]}或相近方向，具备良好的协作与沟通能力。`,
      `对招聘、人才、企业服务类业务有兴趣，结果导向明确。`
    ]
  };
});

const applications = Array.from({ length: 180 }, (_, index) => {
  const job = jobs[index * 2];
  return {
    id: `delivery-${index + 1}`,
    candidate: `候选人${index + 1}`,
    jobId: job.id,
    jobTitle: job.title,
    company: job.company,
    city: job.city,
    salary: job.salary,
    status: ["待沟通", "简历筛选", "约面中", "已发 Offer"][index % 4],
    updatedAt: `2026-03-${String((index % 28) + 1).padStart(2, "0")}`,
    matchScore: 72 + (index % 26)
  };
});

const portalMetrics = [
  { label: "在线岗位", value: jobs.length, suffix: "个" },
  { label: "活跃企业", value: companies.length, suffix: "家" },
  { label: "本周投递", value: applications.length * 3, suffix: "份" },
  { label: "平均反馈", value: 18, suffix: "小时" }
];

export { applications, companies, jobs, portalMetrics };
